const raw = $json ?? {};
const userInput = typeof raw.userInput === 'string' ? raw.userInput.trim() : '';
if (!userInput) {
  throw new Error('AISMR workflow requires a non-empty userInput string.');
}
const sessionId = raw.sessionId && typeof raw.sessionId === 'string' && raw.sessionId.trim().length > 0
  ? raw.sessionId.trim()
  : `aismr:${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
return {
  json: {
    userInput,
    sessionId,
    timestamps: {
      receivedAt: new Date().toISOString()
    }
  }
};

const normalized = $('Normalize Request').item?.json ?? {};
const sessionId = typeof normalized.sessionId === 'string' ? normalized.sessionId.trim() : '';
const content = typeof normalized.userInput === 'string' ? normalized.userInput.trim() : '';
const timestamp = normalized.timestamps?.receivedAt ?? new Date().toISOString();

const metadata = {
  workflow: 'aismr',
  timestamp,
  source: 'n8n-aismr',
};

const payload = sessionId && content
  ? {
      sessionId,
      role: 'user',
      content,
      metadata,
      embeddingText: content,
      userId: normalized.userId ?? null,
    }
  : null;

return {
  json: {
    ...normalized,
    conversationStorePayload: payload,
  },
};

// Prepare agent context with mandatory tooling instructions for AISMR idea generation
const normalized = $('Prepare User Store Request').item?.json ?? $('Normalize Request').item?.json ?? {};
const storeResponse = $('Store User Turn').item?.json ?? {};
const storedTurn = storeResponse.data?.turn ?? null;
const latestLine = storedTurn
  ? `USER (${storedTurn.created_at ?? 'recent'}): ${String(storedTurn.content ?? '').slice(0, 240)}`
  : `USER: ${normalized.userInput}`;

const systemPrompt = [
  'You are Casey, an AI collaborator for Mylo. Keep responses succinct, warm, and actionable.',
  '## Non-negotiable startup steps',
  'Before analysing the request, you MUST execute these tools in order:',
  '1. Call `prompt_get` for the Idea Generator persona using this exact payload (replace the id with your own identifier if needed):',
  '{"jsonrpc":"2.0","id":"persona-load","method":"tools/call","params":{"name":"prompt_get","arguments":{"persona_name":"ideagenerator"}}}',
  '2. Call `prompt_get` for the AISMR project using this exact payload:',
  '{"jsonrpc":"2.0","id":"project-load","method":"tools/call","params":{"name":"prompt_get","arguments":{"project_name":"aismr"}}}',
  'Do not wrap the arguments in strings or include extra fields. If either call fails, retry once and then surface the error to the user.',
  'After both prompts are loaded you may use additional MCP tools as needed.',
  '## Output contract',
  'Respond with JSON that conforms to the schema provided by the Structured Output Parser (userIdea string plus exactly 12 ideas with idea + vibe fields). Return JSON only—no markdown, no prose.',
  '## Latest user input',
  latestLine,
].join('\n\n');

const sessionId = normalized.sessionId;
const timestamp = storedTurn?.created_at ?? normalized.timestamps?.receivedAt ?? new Date().toISOString();

return {
  json: {
    session: {
      id: sessionId,
      originalId: sessionId,
      userId: normalized.userId ?? null,
    },
    message: {
      text: normalized.userInput,
      type: 'text',
      timestamp,
      platform: 'internal',
    },
    systemPrompt,
    conversation: {
      userTurn: storedTurn,
    },
    telemetry: {
      normalize: normalized,
      userStore: storeResponse,
    },
  },
};

const context = $('Assemble Agent Context').item?.json ?? {};
const parsed = $json ?? {};
if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
  throw new Error('AISMR agent response missing structured payload.');
}
if (typeof parsed.userIdea !== 'string' || parsed.userIdea.trim().length === 0) {
  throw new Error('AISMR agent output missing userIdea string.');
}
if (!Array.isArray(parsed.ideas) || parsed.ideas.length !== 12) {
  throw new Error('AISMR agent must return an array of exactly 12 ideas.');
}
for (const [index, idea] of parsed.ideas.entries()) {
  if (!idea || typeof idea !== 'object') {
    throw new Error(`Idea #${index + 1} is not an object.`);
  }
  if (typeof idea.idea !== 'string' || idea.idea.trim().length === 0) {
    throw new Error(`Idea #${index + 1} missing idea text.`);
  }
  if (typeof idea.vibe !== 'string' || idea.vibe.trim().length === 0) {
    throw new Error(`Idea #${index + 1} missing vibe text.`);
  }
}
const rawResponse = JSON.stringify(parsed, null, 2);
const timestamp = new Date().toISOString();
const conversationStorePayload = {
  sessionId: context.session?.id ?? null,
  role: 'assistant',
  content: rawResponse,
  userId: context.session?.userId ?? null,
  metadata: {
    workflow: 'aismr',
    timestamp,
    persona: 'ideagenerator',
    project: 'aismr',
    ideaCount: parsed.ideas.length,
    userIdea: parsed.userIdea,
  },
  embeddingText: rawResponse,
};
return {
  json: {
    sessionId: context.session?.id ?? null,
    userIdea: parsed.userIdea,
    ideas: parsed.ideas,
    rawResponse,
    conversationStorePayload,
    telemetry: {
      agent: parsed,
      context,
    },
  },
};

const response = $('Prepare Response').item?.json ?? {};
const assistantStore = $json ?? {};
const userStore = $('Store User Turn').item?.json ?? {};

return {
  json: {
    sessionId: response.sessionId ?? null,
    userIdea: response.userIdea,
    ideas: response.ideas,
    rawResponse: response.rawResponse,
    telemetry: {
      agent: response.telemetry?.agent ?? null,
      context: response.telemetry?.context ?? null,
      userStore,
      assistantStore,
    },
  },
};

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "userIdea": {
      "type": "string",
      "description": "Normalized base object (lowercase singular) applied to every idea."
    },
    "ideas": {
      "type": "array",
      "description": "Exactly 12 unique AISMR-ready concepts in Title Case descriptor + singular object format.",
      "items": {
        "type": "object",
        "properties": {
          "idea": {
            "type": "string",
            "description": "Title Case descriptor + singular object (two words, descriptor is one word)."
          },
          "vibe": {
            "type": "string",
            "description": "2-4 sentence explanation covering emotion, hook, texture, feasibility, replay value, and environment potential."
          }
        },
        "required": [
          "idea",
          "vibe"
        ],
        "additionalProperties": false
      },
      "minItems": 12,
      "maxItems": 12
    }
  },
  "required": [
    "userIdea",
    "ideas"
  ],
  "additionalProperties": false
}
